 35→function startCommand(options: {
 36→	interval?: string;
 37→	pixels?: string;
 38→	threshold?: string;
 39→	mode?: string;
 40→	verbose?: boolean;
 41→	daemon?: boolean;
 42→}): void {
 43→	const { running, pid } = isDaemonRunning();
 44→	if (running) {
 45→		console.log(`Compliance is already running (PID: ${pid})`);
 46→		console.log('Use "compliance stop" to stop it first.');
 47→		process.exit(1);
 48→	}
 49→
 50→	const config = loadConfig();
 51→
 52→	if (options.interval) {
 53→		const val = parseInt(options.interval, 10);
 54→		const validation = validateInterval(val);
 55→		if (!validation.valid) {
 56→			console.error(`Error: ${validation.error}`);
 57→			process.exit(1);
 58→		}
 59→		config.intervalMs = val;
 60→	}
 61→
 62→	if (options.pixels) {
 63→		const val = parseInt(options.pixels, 10);
 64→		const validation = validatePixels(val);
 65→		if (!validation.valid) {
 66→			console.error(`Error: ${validation.error}`);
 67→			process.exit(1);
 68→		}
 69→		config.movementPx = val;
 70→	}
 71→
 72→	if (options.threshold) {
 73→		const val = parseInt(options.threshold, 10);
 74→		const validation = validateThreshold(val);
 75→		if (!validation.valid) {
 76→			console.error(`Error: ${validation.error}`);
 77→			process.exit(1);
 78→		}
 79→		config.idleThresholdMs = val;
 80→	}
 81→
 82→	if (options.mode) {
 83→		const validation = validateMode(options.mode);
 84→		if (!validation.valid) {
 85→			console.error(`Error: ${validation.error}`);
 86→			process.exit(1);
 87→		}
 88→		config.mode = options.mode as Mode;
 89→	}
 90→
 91→	if (options.verbose !== undefined) {
 92→		config.verbose = options.verbose;
 93→	}
 94→
 95→	if (options.daemon) {
 96→		const __filename = fileURLToPath(import.meta.url);
 97→		const scriptPath = __filename;
 98→
 99→		const args = ["start"];
100→		if (config.verbose) args.push("-v");
101→		args.push("-i", String(config.intervalMs));
102→		args.push("-p", String(config.movementPx));
103→		args.push("-t", String(config.idleThresholdMs));
104→		args.push("-m", config.mode);
105→
106→		const logFd = openSync(LOG_FILE, "a");
107→
108→		const child = spawn("node", [scriptPath, ...args], {
109→			detached: true,
110→			stdio: ["ignore", logFd, logFd],
111→		});
112→
113→		child.unref();
114→
115→		console.log("");
116→		console.log("╔════════════════════════════════════════╗");
117→		console.log("║    Compliance Daemon Started           ║");
118→		console.log("╚════════════════════════════════════════╝");
119→		console.log("");
120→		console.log(`  PID: ${child.pid}`);
121→		console.log(`  Log: ${LOG_FILE}`);
122→		console.log("");
123→		console.log("Commands:");
124→		console.log("  compliance status  - Check status");
125→		console.log("  compliance logs    - View logs");
126→		console.log("  compliance stop    - Stop daemon");
127→		console.log("");
128→		process.exit(0);
129→	}
130→
131→	console.log("");
132→	console.log("╔════════════════════════════════════════╗");
133→	console.log(`║    Compliance v${VERSION}                   ║`);
134→	console.log("╚════════════════════════════════════════╝");
135→	console.log("");
136→	console.log("Press Ctrl+C to stop");
137→	console.log("");
138→
139→	const daemon = new ComplianceDaemon(config);
140→	daemon.start();
141→}
