215→function configCommand(action?: string, key?: string, value?: string): void {
216→	if (!action) {
217→		const config = loadConfig();
218→		console.log("");
219→		console.log(formatConfig(config));
220→		console.log("");
221→		console.log(`Config file: ${CONFIG_DIR}/config.json`);
222→		console.log("");
223→		console.log("Usage:");
224→		console.log("  compliance config set <key> <value>  - Set a value");
225→		console.log("  compliance config get <key>          - Get a value");
226→		console.log("  compliance config reset              - Reset to defaults");
227→		console.log("");
228→		console.log("Keys: intervalMs, movementPx, idleThresholdMs, mode, verbose");
229→		console.log("");
230→		return;
231→	}
232→
233→	if (action === "reset") {
234→		resetConfig();
235→		resetStats();
236→		console.log("Configuration and stats reset to defaults.");
237→		return;
238→	}
239→
240→	if (action === "get") {
241→		if (!key) {
242→			console.error("Usage: compliance config get <key>");
243→			process.exit(1);
244→		}
245→		const config = loadConfig();
246→		const validKeys = Object.keys(config);
247→		if (!validKeys.includes(key)) {
248→			console.error(`Unknown key: ${key}`);
249→			console.error(`Valid keys: ${validKeys.join(", ")}`);
250→			process.exit(1);
251→		}
252→		console.log(`${key}: ${config[key as keyof Config]}`);
253→		return;
254→	}
255→
256→	if (action === "set") {
257→		if (!key || !value) {
258→			console.error("Usage: compliance config set <key> <value>");
259→			process.exit(1);
260→		}
261→
262→		const config = loadConfig();
263→		const validKeys = Object.keys(config);
264→		if (!validKeys.includes(key)) {
265→			console.error(`Unknown key: ${key}`);
266→			console.error(`Valid keys: ${validKeys.join(", ")}`);
267→			process.exit(1);
268→		}
269→
270→		const { parsed, error } = parseConfigValue(key as keyof Config, value);
271→		if (error || parsed === null) {
272→			console.error(`Error: ${error || "Invalid value"}`);
273→			process.exit(1);
274→		}
275→
276→		const result = setConfigValue(key as keyof Config, parsed);
277→		if (!result.valid) {
278→			console.error(`Error: ${result.error}`);
279→			process.exit(1);
280→		}
281→
282→		console.log(`Set ${key} = ${parsed}`);
283→		return;
284→	}
285→
286→	console.error(`Unknown action: ${action}`);
287→	console.error("Valid actions: set, get, reset");
288→	process.exit(1);
289→}
