319→function autostartCommand(action?: string): void {
320→	const status = getAutostartStatus();
321→
322→	if (!action) {
323→		console.log("");
324→		console.log(formatAutostartStatus());
325→		console.log("");
326→		console.log("Usage:");
327→		console.log("  compliance autostart enable   - Enable autostart on login");
328→		console.log("  compliance autostart disable  - Disable autostart");
329→		console.log("");
330→		if (status.enabled) {
331→			console.log(`Plist: ${status.plistPath}`);
332→			console.log("");
333→		}
334→		return;
335→	}
336→
337→	if (action === "enable") {
338→		if (status.enabled && status.loaded) {
339→			console.log("Autostart is already enabled and loaded.");
340→			return;
341→		}
342→
343→		const result = enableAutostart();
344→		if (result.success) {
345→			console.log("");
346→			console.log("✅ Autostart enabled");
347→			console.log("");
348→			console.log("Compliance will start automatically on login.");
349→			console.log("");
350→			console.log("Commands:");
351→			console.log("  launchctl list | grep compliance  - Check if loaded");
352→			console.log("  compliance autostart disable      - Disable autostart");
353→			console.log("");
354→		} else {
355→			console.error(`Failed to enable autostart: ${result.error}`);
356→			process.exit(1);
357→		}
358→		return;
359→	}
360→
361→	if (action === "disable") {
362→		if (!status.enabled) {
363→			console.log("Autostart is already disabled.");
364→			return;
365→		}
366→
367→		const result = disableAutostart();
368→		if (result.success) {
369→			console.log("");
370→			console.log("✅ Autostart disabled");
371→			console.log("");
372→		} else {
373→			console.error(`Failed to disable autostart: ${result.error}`);
374→			process.exit(1);
375→		}
376→		return;
377→	}
378→
379→	console.error(`Unknown action: ${action}`);
380→	console.error("Valid actions: enable, disable");
381→	process.exit(1);
382→}
