 66→export function validateInterval(value: number): ValidationResult {
 67→	if (Number.isNaN(value) || value < MIN_INTERVAL_MS) {
 68→		return {
 69→			valid: false,
 70→			error: `Interval must be >= ${MIN_INTERVAL_MS}ms`,
 71→		};
 72→	}
 73→	return { valid: true };
 74→}
