 76→export function validatePixels(value: number): ValidationResult {
 77→	if (Number.isNaN(value) || value < 1 || value > MAX_PIXELS) {
 78→		return {
 79→			valid: false,
 80→			error: `Pixels must be between 1 and ${MAX_PIXELS}`,
 81→		};
 82→	}
 83→	return { valid: true };
 84→}
 85→
 86→export function validateThreshold(value: number): ValidationResult {
 87→	if (Number.isNaN(value) || value < MIN_THRESHOLD_MS) {
 88→		return {
 89→			valid: false,
 90→			error: `Threshold must be >= ${MIN_THRESHOLD_MS}ms`,
 91→		};
 92→	}
 93→	return { valid: true };
 94→}
