106→export function validateConfigValue<K extends keyof Config>(
107→	key: K,
108→	value: Config[K],
109→): ValidationResult {
110→	switch (key) {
111→		case "intervalMs":
112→			return validateInterval(value as number);
113→		case "movementPx":
114→			return validatePixels(value as number);
115→		case "idleThresholdMs":
116→			return validateThreshold(value as number);
117→		case "mode":
118→			return validateMode(value as string);
119→		case "verbose":
120→			if (typeof value !== "boolean") {
121→				return {
122→					valid: false,
123→					error: "Verbose must be true or false",
124→				};
125→			}
126→			return { valid: true };
127→		default:
128→			return {
129→				valid: false,
130→				error: `Unknown config key: ${key}`,
131→			};
132→	}
133→}
