135→export function parseConfigValue(
136→	key: keyof Config,
137→	value: string,
138→): {
139→	parsed: Config[keyof Config] | null;
140→	error?: string;
141→} {
142→	switch (key) {
143→		case "intervalMs":
144→		case "movementPx":
145→		case "idleThresholdMs": {
146→			const num = parseInt(value, 10);
147→			if (Number.isNaN(num)) {
148→				return {
149→					parsed: null,
150→					error: `Invalid number: ${value}`,
151→				};
152→			}
153→			return { parsed: num };
154→		}
155→		case "mode":
156→			return { parsed: value as Mode };
157→		case "verbose":
158→			if (value === "true" || value === "1") return { parsed: true };
159→			if (value === "false" || value === "0") return { parsed: false };
160→			return {
161→				parsed: null,
162→				error: "Verbose must be true or false",
163→			};
164→		default:
165→			return {
166→				parsed: null,
167→				error: `Unknown key: ${key}`,
168→			};
169→	}
170→}
