108→export function enableAutostart(): { success: boolean; error?: string } {
109→	try {
110→		if (!existsSync(LAUNCH_AGENTS_DIR)) {
111→			mkdirSync(LAUNCH_AGENTS_DIR, { recursive: true });
112→		}
113→
114→		if (!existsSync(CONFIG_DIR)) {
115→			mkdirSync(CONFIG_DIR, { recursive: true });
116→		}
117→
118→		createWrapperScript();
119→
120→		const plistContent = generatePlist();
121→		writeFileSync(PLIST_PATH, plistContent, "utf-8");
122→
123→		try {
124→			execSync(`launchctl unload "${PLIST_PATH}" 2>/dev/null`, {
125→				encoding: "utf-8",
126→			});
127→		} catch {
128→			// Ignore if not loaded
129→		}
130→
131→		execSync(`launchctl load "${PLIST_PATH}"`, { encoding: "utf-8" });
132→
133→		return { success: true };
134→	} catch (err) {
135→		return {
136→			success: false,
137→			error: err instanceof Error ? err.message : String(err),
138→		};
139→	}
140→}
