145→			try {
146→				execSync(`launchctl unload "${PLIST_PATH}"`, { encoding: "utf-8" });
147→			} catch {
148→				// Ignore unload errors
149→			}
150→		}
151→
152→		if (existsSync(PLIST_PATH)) {
153→			unlinkSync(PLIST_PATH);
154→		}
155→
156→		if (existsSync(WRAPPER_PATH)) {
157→			unlinkSync(WRAPPER_PATH);
158→		}
159→
160→		return { success: true };
161→	} catch (err) {
162→		return {
163→			success: false,
164→			error: err instanceof Error ? err.message : String(err),
165→		};
166→	}
167→}
